import { useEffect, useState } from "react";
// todo-api-client.ts is generated by: tesl generate ts todo-api.tesl
import {
  Todo,
  NewTodoSchema,
  TodoIdSchema,
  getTodosMine as listMyTodos,
  getTodosMineOpen as listMyOpenTodos,
  postTodos as createTodo,
  putTodosComplete as completeTodo,
  configure,
  // getTodos(todoId) — requires a branded TodoId, not a plain string.
  // Call TodoIdSchema.parse(rawId) first.
} from "./todo-api-client";

// Derived from the generated schema — stays in sync if constraints change.
const TitleSchema = NewTodoSchema.shape.title;

// Point the generated client at your backend
configure("http://localhost:8086");

// ---------------------------------------------------------------------------
// Cookie helpers — the API uses a plain `user` cookie for auth (dev only)
// ---------------------------------------------------------------------------

function getUserCookie(): string | null {
  const match = document.cookie.match(/(?:^|;\s*)user=([^;]+)/);
  return match ? decodeURIComponent(match[1]) : null;
}

function setUserCookie(userId: string) {
  document.cookie = `user=${encodeURIComponent(userId)}; path=/`;
}

